generated_oml:
// C3: Physical sensing components
instance MotorPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Encoder mounted on the permanent‑magnet synchronous motor providing motor‑side position signals"
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxPositionEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder located behind the gearbox providing gearbox‑side position signals"
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring motor input current I_M from the Siemens SINUMERIK 840D controller"
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C4: Physical-to-virtual interaction
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorPositionEncoder
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxPositionEncoder
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data
instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of motor side angular position r_M"
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

instance GearboxEncoderData : DTDFVocab:Data [
    base:desc "Time‑series of gearbox side angular position r_G"
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Measured motor current I_M"
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo MQTTEnabler, SimulinkEnabler
]

// C10: Models
instance SysMLStructureModel : DTDFVocab:Model [
    base:desc "SysML block‑definition and internal‑block diagram describing the robot axis structure and ports"
    DTDFVocab:inputTo AssetAdministrationShell
]

instance SimulinkMotorModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink white‑box model of the permanent‑magnet synchronous motor for torque and speed simulation"
    DTDFVocab:inputTo SimulinkEnabler, RealTimeFrictionIdentificationService
]

instance SimulinkGearboxModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink black‑box model of the gearbox and cycloidal gear for output angle and torque simulation"
    DTDFVocab:inputTo SimulinkEnabler, RealTimeFrictionIdentificationService
]

instance FrictionIdentificationModel : DTDFVocab:Model [
    base:desc "Data‑calculation model deriving static, kinetic and viscous friction parameters τ and ω from sensor streams"
    DTDFVocab:inputTo RealTimeFrictionIdentificationService
]

// C11: Enablers
instance MQTTEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker streaming live sensor data from the robot to the digital shadow"
    DTDFVocab:enables RealTimeFrictionIdentificationService, SimulatedDataGenerationService
]

instance SimulinkEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink execution environment used to run motor and gearbox simulation models"
    DTDFVocab:enables SimulatedDataGenerationService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell encapsulating engineering and simulation models for interoperability"
    DTDFVocab:enables ModelRepositoryService
]

instance CustomDashboardEnabler : DTDFVocab:Enabler [
    base:desc "Custom web dashboard visualizing data traces and friction identification results"
    DTDFVocab:enables DataVisualizationService
]

// C6: Services
instance RealTimeFrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time identification of static, kinetic and viscous friction in the gearbox"
    DTDFVocab:provides FrictionParameterInsight, AdjustControlAlgorithmAction
]

instance SimulatedDataGenerationService : DTDFVocab:Service [
    base:desc "Generation of simulated torque and angular velocity data using white‑box and black‑box Simulink models"
    DTDFVocab:provides SimulatedDataInsight
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Interactive visualization of measured vs. simulated data traces and friction parameters"
    DTDFVocab:provides DeviationAnalysisInsight
]

instance ModelRepositoryService : DTDFVocab:Service [
    base:desc "Repository service providing access to encapsulated SysML and Simulink models via the AAS"
    DTDFVocab:provides ModelAvailabilityInsight
]

// C17: Insights / Actions
instance FrictionParameterInsight : DTDFVocab:Insight [
    base:desc "Identified friction parameters (static, kinetic, viscous) are available for controller tuning"
]

instance AdjustControlAlgorithmAction : DTDFVocab:Action [
    base:desc "Adjustment of robot control algorithms using derived friction parameters to improve motion accuracy"
    DTDFVocab:IsAutomatic true
]

instance SimulatedDataInsight : DTDFVocab:Insight [
    base:desc "Simulated torque and velocity data enable comparison with measured signals"
]

instance DeviationAnalysisInsight : DTDFVocab:Insight [
    base:desc "Dashboard analysis of deviation between measured and simulated data supports parameter updates"
]

instance ModelAvailabilityInsight : DTDFVocab:Insight [
    base:desc "Engineered and simulation models are accessible through the Asset Administration Shell"
]

instance virtual_to_physical_interaction : DTDFVocab:VirtualToPhysical [
    base:desc "The digital shadow does not send commands back to the robot; it is a one‑way (physical‑to‑virtual) data flow as defined for a digital shadow."
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous, online synchronization with the live sensor streams (real‑time data acquisition), enabling near‑instantaneous update of the digital shadow during robot operation."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow consisting of a purpose (FrictionDerivation), an asset (MABI robot first axis), sources (sensor channels), processing components (Simulation_M, Simulation_GW, Simulation_GB), models (engineering, simulation and data‑calculation), and data traces that are linked via the Digital Shadow Reference Model."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Full traceability of each data point to its source and processing component, use of both white‑box (analytical) and black‑box (data‑driven) friction models for multi‑physics‑aware identification, and continuous re‑identification to account for wear, temperature and load changes."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "Sensor data are transmitted from the robot to the digital shadow over MQTT; the digital shadow processes these MQTT messages to generate data traces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation follows Industry 4.0 standards such as the Asset Administration Shell (AAS) and uses standardized modeling languages (SysML) and protocols (MQTT)."
]
